    let numbering
    if (numarr !== 0) {
      numbering = numarr
    } else {
      numbering = this.obj
    }

    const vbn = numbering.filter(item => {
      return isNaN(item)
    })

    const bvc = numbering.indexOf(vbn[0])
    if (bvc !== -1) {
      throw new result(list[bvc], 202)
